import{_ as o,c as s,o as n,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"Connect to DeepSeek (Recommended)","description":"Get your DeepSeek API Key and complete your first conversation in OpenCode.","frontmatter":{"title":"Connect to DeepSeek (Recommended)","subtitle":"Direct access, affordable, and powerful","course":"OpenCode Practical Course","stage":"Stage 1","lesson":"1.4b","duration":"10 min","practice":"5 min","level":"Beginner","description":"Get your DeepSeek API Key and complete your first conversation in OpenCode.","tags":["Model","DeepSeek","API Key"],"prerequisite":["1.2 Installation"]},"headers":[],"relativePath":"en/1-start/04b-deepseek.md","filePath":"en/1-start/04b-deepseek.md","lastUpdated":1772014034000}'),r={name:"en/1-start/04b-deepseek.md"};function i(l,a,c,d,p,h){return n(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="connect-to-deepseek-recommended" tabindex="-1">Connect to DeepSeek (Recommended) <a class="header-anchor" href="#connect-to-deepseek-recommended" aria-label="Permalink to “Connect to DeepSeek (Recommended)”">​</a></h1><blockquote><p>Estimated time: 5-10 minutes</p></blockquote><p>DeepSeek is great for beginners: direct access (no VPN needed in most regions), simple registration, extremely affordable, and strong coding capabilities.</p><p>If you haven&#39;t read &quot;What is an API Key&quot;, we recommend going back to <a href="./04-connect.html">1.4 Overview</a> to understand the concepts first.</p><hr><h2 id="what-you-ll-be-able-to-do" tabindex="-1">What You&#39;ll Be Able to Do <a class="header-anchor" href="#what-you-ll-be-able-to-do" aria-label="Permalink to “What You&#39;ll Be Able to Do”">​</a></h2><ul><li>Get a DeepSeek API Key</li><li>Connect DeepSeek in OpenCode</li><li>Send your first message and receive a response</li></ul><hr><h2 id="🎒-before-you-start" tabindex="-1">🎒 Before You Start <a class="header-anchor" href="#🎒-before-you-start" aria-label="Permalink to “🎒 Before You Start”">​</a></h2><ul><li>[ ] Completed <a href="./02-install.html">1.2 Installation</a> and can run <code>opencode</code></li><li>[ ] Can access <code>https://platform.deepseek.com</code></li></ul><hr><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to “Follow Along”">​</a></h2><h3 id="step-1-register-a-deepseek-account" tabindex="-1">Step 1: Register a DeepSeek Account <a class="header-anchor" href="#step-1-register-a-deepseek-account" aria-label="Permalink to “Step 1: Register a DeepSeek Account”">​</a></h3><p>Visit: <a href="https://platform.deepseek.com" target="_blank" rel="noreferrer">https://platform.deepseek.com</a></p><p>Click &quot;Login/Register&quot; in the top right corner, and follow the prompts to register with your phone number or email.</p><hr><h3 id="step-2-get-your-api-key" tabindex="-1">Step 2: Get Your API Key <a class="header-anchor" href="#step-2-get-your-api-key" aria-label="Permalink to “Step 2: Get Your API Key”">​</a></h3><p>Go to the API Keys page:</p><ul><li>Left menu in console: <code>API Keys</code></li><li>Or visit directly: <a href="https://platform.deepseek.com/api_keys" target="_blank" rel="noreferrer">https://platform.deepseek.com/api_keys</a></li></ul><p>Create a new Key and <strong>copy and save it immediately</strong>.</p><div class="warning custom-block"><p class="custom-block-title">Only shown once!</p><p>Most platforms only display the Key once. Once you close the window, you won&#39;t be able to see the complete Key again.</p><p>Please copy it to a safe place (password manager/notes) immediately. Don&#39;t share it in group chats, don&#39;t screenshot it, don&#39;t commit it to GitHub.</p></div><hr><h3 id="step-3-optional-but-recommended-add-credits" tabindex="-1">Step 3: (Optional but Recommended) Add Credits <a class="header-anchor" href="#step-3-optional-but-recommended-add-credits" aria-label="Permalink to “Step 3: (Optional but Recommended) Add Credits”">​</a></h3><p>DeepSeek usually gives new users a small amount of credits, but they run out quickly. Adding about 10 CNY worth of credits will last you a long time.</p><hr><h3 id="step-4-connect-deepseek-in-opencode" tabindex="-1">Step 4: Connect DeepSeek in OpenCode <a class="header-anchor" href="#step-4-connect-deepseek-in-opencode" aria-label="Permalink to “Step 4: Connect DeepSeek in OpenCode”">​</a></h3><p>Start OpenCode:</p>',27),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode")])],-1),e("p",null,"In the input box, enter:",-1),e("div",{class:"language-"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"}),e("pre",null,[e("code",{"v-pre":""},"/connect")])],-1),t('<p>Select <code>DeepSeek</code> from the provider list, then paste your API Key.</p><p>After success, you&#39;ll enter the model selection interface showing DeepSeek&#39;s available models (such as <code>deepseek-chat</code>, <code>deepseek-reasoner</code>). Select a model to start chatting.</p><hr><h3 id="step-5-send-your-first-message-verify-success" tabindex="-1">Step 5: Send Your First Message (Verify Success) <a class="header-anchor" href="#step-5-send-your-first-message-verify-success" aria-label="Permalink to “Step 5: Send Your First Message (Verify Success)”">​</a></h3><p>In the input box, enter:</p>',5),e("div",{class:"language-"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"}),e("pre",null,[e("code",{"v-pre":""},"Hello, please introduce yourself")])],-1),t('<p>If you receive a response, the connection is successful.</p><hr><h2 id="checklist-✅" tabindex="-1">Checklist ✅ <a class="header-anchor" href="#checklist-✅" aria-label="Permalink to “Checklist ✅”">​</a></h2><ul><li>[ ] Sending messages receives AI responses</li><li>[ ] No errors (such as <code>API key invalid</code> / <code>insufficient balance</code> / <code>connection timeout</code>)</li></ul><hr><h2 id="common-issues" tabindex="-1">Common Issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to “Common Issues”">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Cause</th><th>Solution</th></tr></thead><tbody><tr><td><code>API key invalid</code></td><td>Key copied incorrectly or has extra spaces</td><td>Copy again, make sure there are no extra spaces</td></tr><tr><td><code>insufficient balance</code></td><td>Insufficient balance</td><td>Add credits in the console</td></tr><tr><td><code>connection timeout</code></td><td>Network fluctuation</td><td>Wait a moment and try again</td></tr></tbody></table><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><ul><li>Go back to <a href="./04-connect.html">1.4 Overview</a> to choose your next path, or proceed to <a href="./../2-daily/01-interface.html">2.1 Interface &amp; Basic Operations</a></li></ul><div class="tip custom-block"><p class="custom-block-title">Having issues?</p><p>Stuck during configuration? <a href="/en/community.html">Join the community</a> to connect with 2000+ fellow learners for real-time support.</p></div>',11)])])}const f=o(r,[["render",i]]);export{m as __pageData,f as default};
